function kebabToCamel(input: string): string {
  if (!input || input.length === 0) {
    throw new SyntaxError('Input must not be empty');
  }

  if (!/^[a-z]+(-[a-z]+)*$/.test(input)) {
    if (input.startsWith('-') || input.endsWith('-')) {
      throw new SyntaxError('Input must not start or end with a hyphen');
    }
    if (/--/.test(input)) {
      throw new SyntaxError('Input must not contain consecutive hyphens');
    }
    throw new SyntaxError(`Invalid kebab-case input: ${JSON.stringify(input)}`);
  }

  return input
    .split('-')
    .map((part, index) => index === 0 ? part : part.charAt(0).toUpperCase() + part.slice(1))
    .join('');
}

export { kebabToCamel };
export default kebabToCamel;
